	// Start of user code block custom items
	// End of user code block custom items
	private static <I extends Item> DeferredItem<I> register(String name, Function<Item.Properties, ? extends I> supplier) {
		return REGISTRY.registerItem(name, supplier, new Item.Properties());
	}

	private static DeferredItem<Item> block(DeferredHolder<Block, Block> block) {
		return block(block, new Item.Properties());
	}

	private static DeferredItem<Item> block(DeferredHolder<Block, Block> block, Item.Properties properties) {
		return REGISTRY.registerItem(block.getId().getPath(), prop -> new BlockItem(block.get(), prop), properties);
	}

	@SubscribeEvent
	public static void registerCapabilities(RegisterCapabilitiesEvent event) {
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new EngieBundleInventoryCapability(stack), ENGIE_BUNDLE.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new AngryEngieBundleInventoryCapability(stack), ANGRY_ENGIE_BUNDLE.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new EnragedEngieBundleInventoryCapability(stack), ENRAGED_ENGIE_BUNDLE.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new OutragedEngieBundleInventoryCapability(stack), OUTRAGED_ENGIE_BUNDLE.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new BiblicallyAccurateEngieBundleInventoryCapability(stack), BIBLICALLY_ACCURATE_ENGIE_BUNDLE.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new MonstrosityEngieBundleInventoryCapability(stack), MONSTROSITY_ENGIE_BUNDLE.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new DeveloperEngieBundleInventoryCapability(stack), DEVELOPER_ENGIE_BUNDLE.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new IdeagiverEngieBundleInventoryCapability(stack), IDEAGIVER_ENGIE_BUNDLE.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new TesterEngieBundleInventoryCapability(stack), TESTER_ENGIE_BUNDLE.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new ContentCreatorEngieBundleInventoryCapability(stack), CONTENT_CREATOR_ENGIE_BUNDLE.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new CreativeEngieBundleInventoryCapability(stack), CREATIVE_ENGIE_BUNDLE.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new EngiesOwnEngieBundleInventoryCapability(stack), ENGIES_OWN_ENGIE_BUNDLE.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new EngiesBirthdayBundleInventoryCapability(stack), ENGIES_BIRTHDAY_BUNDLE25.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new EngieBirthdayBundleForYoungestInventoryCapability(stack), ENGIE_BIRTHDAY_BUNDLE_FOR_YOUNGEST.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new AllAboutEngieRecipeBookInventoryCapability(stack), ALL_ABOUT_ENGIE_RECIPE_BOOK.get());
		event.registerItem(Capabilities.ItemHandler.ITEM, (stack, context) -> new RegularEngieBundleInventoryCapability(stack), REGULAR_ENGIE_BUNDLE.get());
	}
